  function ensureInventoryPanel() {
    if (!dom.inventorySummary || !dom.inventoryList) {
      const panel = document.createElement("section");
      panel.className = "panel inventory-panel";
      panel.setAttribute("aria-labelledby", "inventoryTitle");
      panel.dataset.workspacePanel = "resources";
      panel.innerHTML = `
        <div class="panel-heading">
          <div>
            <h2 id="inventoryTitle">Inventory</h2>
            <p id="inventorySummary">Storage Room ledger</p>
          </div>
        </div>
        <div id="inventoryList" class="inventory-list"></div>
      `;
      const scientistPanel = document.querySelector(".scientist-panel");
      if (scientistPanel?.parentElement) {
        scientistPanel.parentElement.insertBefore(panel, scientistPanel.nextSibling);
      } else {
        dom.labRoot?.append(panel);
      }
      dom.inventorySummary = document.getElementById("inventorySummary");
      dom.inventoryList = document.getElementById("inventoryList");
    }

    if (!dom.inventoryCommandInput || !dom.inventoryCommandBtn || !dom.inventoryCommandStatus) {
      const cheatGrid = document.querySelector(".cheat-grid");
      if (cheatGrid) {
        const subpanel = document.createElement("div");
        subpanel.className = "subpanel";
        subpanel.dataset.inventoryCheatPanel = "true";
        subpanel.innerHTML = `
          <div class="subpanel-title">Inventory Cheat</div>
          <div class="cheat-row">
            <input id="inventoryCommandInput" type="text" spellcheck="false" placeholder="pick 1 storage or damage pick 20">
            <button id="inventoryCommandBtn" type="button">Apply</button>
          </div>
          <p id="inventoryCommandStatus" class="journal-meta">Add/remove items, or use damage/restore/quality for durable tools.</p>
        `;
        cheatGrid.append(subpanel);
        dom.inventoryCommandInput = document.getElementById("inventoryCommandInput");
        dom.inventoryCommandBtn = document.getElementById("inventoryCommandBtn");
        dom.inventoryCommandStatus = document.getElementById("inventoryCommandStatus");
      }
    }

  }

  function populateTimeSpeedSelect() {
    dom.timeSpeedSelect.textContent = "";
    for (const speed of TIME_SPEEDS) {
      const option = document.createElement("option");
      option.value = speed.id;
      option.textContent = `${speed.label} (${speed.description})`;
      dom.timeSpeedSelect.append(option);
    }
  }

  function populateMessageFilterSelect() {
    if (!dom.messageFilterSelect) {
      return;
    }
    dom.messageFilterSelect.textContent = "";
    const allOption = document.createElement("option");
    allOption.value = DEFAULT_MESSAGE_FILTER;
    allOption.textContent = "All messages";
    dom.messageFilterSelect.append(allOption);
    for (const category of MESSAGE_CATEGORY_DEFS) {
      const option = document.createElement("option");
      option.value = category.id;
      option.textContent = category.label;
      dom.messageFilterSelect.append(option);
    }
  }

  function installDebugHooks() {
    window.helixHeresyDebug = {
      mapViewSnapshot: () => buildLabMapView(),
      mapDomSnapshot: () => buildLabMapView().cells.map(labMapCellDomModel),
      navigationSnapshot: () => ({
        revisions: normalizeNavigationState(state.navigation),
        planner: navigationService.snapshot(),
        reservations: movementReservations.snapshot(state.clock),
        actors: [
          { id: "scientist", roomId: scientistRoomId(), cell: scientistMapCell(), footprint: navigationFootprintForActor(state.scientist) },
          ...(state.slimes || []).filter((slime) => slimeIsUncontained(slime) && slime.status !== "dead").map((slime) => ({
            id: slime.id,
            cell: objectMapCell(slime),
            footprint: navigationFootprintForActor(slime),
            movement: slime.autonomousMovement ? normalizeSlimeAutonomousMovement(slime.autonomousMovement) : null
          }))
        ]
      }),
      simulationPerformanceSnapshot: () => buildSimulationPerformanceSnapshot(),
      resetSimulationPerformance: () => {
        simulationPerformance.systems = {};
        for (const key of ["render", "save"]) simulationPerformance[key] = { calls: 0, totalMs: 0, lastMs: 0, maxMs: 0 };
        simulationPerformance.lastAdvanceMs = 0;
        simulationPerformance.maxAdvanceMs = 0;
        return buildSimulationPerformanceSnapshot();
      },
      navigationPlan: (fromCell, toCell, actorId = "scientist", options = {}) => labNavigationPlanBetweenCells(fromCell, toCell, {
        map: ensureLabMap(),
        actor: actorId === "scientist" ? state.scientist : findSlime(actorId),
        ignoreDoors: Boolean(options.ignoreDoors),
        ignoreAccessPolicy: Boolean(options.ignoreAccessPolicy)
      }),
      verticalMapSnapshot: () => ({
        activeLayer: mapViewportForUi().z,
        layerHeightM: ensureLabMap().layerHeightM,
        connectors: (ensureLabMap().terrain?.verticalConnectors || []).map((entry) => ({
          ...entry,
          lowerCell: { ...entry.lowerCell },
          upperCell: { ...entry.upperCell }
        })),
        excavated: (ensureLabMap().terrain?.excavated || []).map((cell) => ({ ...cell }))
      }),
      setMapLayer: (z) => {
        const current = mapViewportForUi().z;
        setMapLayer(Number(z) - current);
        return mapViewportForUi().z;
      },
      designateVerticalExcavation: (mode, cell) => {
        if (!["stairUp", "stairDown", "channelDown"].includes(mode)) return false;
        return createConstructionOrder(mode, [cleanMapCell(cell)], { label: constructionOrderLabel(mode, [cell]) });
      },
      testScientistGravityAt: (cell) => {
        state.scientist.mapCell = cleanMapCell(cell);
        const beforeHealth = scientistVital("health").current;
        const moved = applyGravityAfterTopologyChange();
        persist();
        render();
        return { moved, cell: { ...state.scientist.mapCell }, beforeHealth, health: scientistVital("health").current };
      },
      slimeAiSnapshot: (slimeId) => {
        const slime = findSlime(slimeId);
        return slime ? {
          actual: slimeAiRecord(slime),
          observed: slimeObservedAiRecord(slime),
          activity: slime.roomActivity ? { ...slime.roomActivity } : null,
          movement: slime.autonomousMovement ? { ...slime.autonomousMovement } : null
        } : null;
      },
      reevaluateSlimeIntent: (slimeId) => {
        const slime = findSlime(slimeId);
        if (!slime || slime.status === "dead") return false;
        slime.nextAutonomousDecisionAt = state.clock;
        if (slimeIsUncontained(slime)) chooseAutonomousSlimeActivity(slime);
        syncSlimeAi(slime);
        persist();
        render();
        return true;
      },
      startSlimeMovementTo: (slimeId, target) => {
        const slime = findSlime(slimeId);
        if (!slime || !slimeIsUncontained(slime)) return false;
        const cleanTarget = {
          ...target,
          roomId: cleanRoomId(target?.roomId || slimeEffectiveRoomId(slime)),
          cell: cleanMapCell(target?.cell)
        };
        cleanTarget.cell ||= targetCellForRoomTarget(cleanTarget.roomId);
        const path = pathToAutonomousTarget(slime, cleanTarget);
        const started = startSlimeAutonomousMovement(slime, cleanTarget, path);
        if (started) {
          syncSlimeAi(slime);
          persist();
          render();
        }
        return started;
      },
      relocateLooseSlime: (slimeId, cell) => {
        const slime = findSlime(slimeId);
        const target = cleanMapCell(cell);
        if (!slime || !slimeIsUncontained(slime) || !target || !labMapCellIsWalkable(target)) return false;
        slime.mapCell = target;
        slime.roomId = labMapCellRoomId(target) || slime.roomId;
        slime.autonomousMovement = null;
        slime.nextAutonomousDecisionAt = state.clock + CREATURE_AUTONOMOUS_DECISION_INTERVAL;
        slime.roomActivity = { type: "quiescent", label: "remaining quiescent", roomId: slime.roomId, updatedAt: state.clock };
        rebuildActorSpatialIndex();
        updateSensorySystems(0, { force: true });
        refreshIncidentAlerts();
        persist();
        render();
        return true;
      },
      startSlimeMovementThroughDoor: (slimeId, doorId) => {
        const slime = findSlime(slimeId);
        const mapDoor = labMapDoor(doorId);
        const origin = objectMapCell(slime);
        if (!slime || !slimeIsUncontained(slime) || !mapDoor || !origin) return false;
        const target = {
          kind: "residue",
          id: `beyond-${doorId}`,
          label: "food trace beyond the door",
          roomId: mapDoor.roomIds.find((roomId) => roomId !== slimeEffectiveRoomId(slime)) || mapDoor.roomIds[0],
          cell: mapDoor.cell
        };
        const path = labMapPathBetweenCells(origin, mapDoor.cell, { map: ensureLabMap() });
        const started = startSlimeAutonomousMovement(slime, target, path);
        if (started) {
          syncSlimeAi(slime);
          persist();
          render();
        }
        return started;
      },
      setDoorPhysicalState: (doorId, nextState) => {
        const changed = setDoorState("", "", nextState, { doorId, event: false });
        if (changed) {
          persist();
          render();
        }
        return changed;
      },
      rememberSlimeFailure: (slimeId, intent, target, options = {}) => {
        const slime = findSlime(slimeId);
        if (!slime) return null;
        const failure = recordSlimeIntentFailure(slime, intent, target, options.reason || "debug failure", { painful: Boolean(options.painful) });
        syncSlimeAi(slime);
        persist();
        render();
        return failure;
      },
      accessControlSnapshot: () => JSON.parse(JSON.stringify(ensureAccessControl())),
      accessBlockReasons: (path, actorId = "scientist") => pathAccessBlockReasons(actorId === "scientist" ? state.scientist : findSlime(actorId), path),
      startScientistMove: (roomId, options = {}) => startScientistMove(roomId, options),
      combatSnapshot: () => ({
        ...normalizeCombatState(state.combat),
        actions: Object.fromEntries(Object.entries(COMBAT_ACTION_DEFS).map(([id, action]) => [id, { ...action }])),
        scientistGuarding: scientistGuarding()
      }),
      startScientistCombatAction: (actionId, slimeId) => beginScientistCombatAction(actionId, slimeId),
      setScientistGuarding: (guarding) => guarding
        ? (scientistGuarding() || startScientistGuard())
        : (!scientistGuarding() || stopScientistGuardAndRender()),
      cancelScientistCombatAction: () => {
        const changed = cancelPendingScientistCombatAction();
        persist();
        render();
        return changed;
      },
      startSlimeRecapture: (slimeId, containerId) => startSlimeRecapture(slimeId, containerId),
      startPlaceBait: (cell, feedstockKey) => startPlaceBait(cell, feedstockKey),
      containmentResponseSnapshot: (slimeId = "") => {
        const slime = slimeId ? findSlime(slimeId) : null;
        return {
          slime: slime ? { id: slime.id, status: slime.status, containerId: slime.containerId, cell: objectMapCell(slime) } : null,
          incident: slime ? looseSlimeIncident(slime) : null,
          destinations: slime ? recaptureDestinationCandidates(slime).map((container) => ({
            id: container.id,
            name: container.name,
            blockReason: recaptureSlimeBlockReason(slime, container),
            risk: recaptureRiskAssessment(slime, container, { knownOnly: true }).band
          })) : [],
          tasks: scientistQueueTasks().filter((task) => ["recaptureSlime", "placeBait"].includes(task.type)).map((task) => ({ ...task, data: { ...task.data } }))
        };
      },
      selectMapTarget: (target) => {
        const selection = setSelection(target, { source: "map", centerMap: true });
        persist();
        render();
        return selection;
      },
      taskStatusSnapshot: () => scientistQueueTasks().map((task) => ({
        id: task.id,
        type: task.type,
        label: task.label,
        createdAt: task.createdAt,
        dueAt: task.dueAt,
        status: taskStatusInfo(task),
        data: { ...task.data }
      })),
      workOrderSnapshot: () => ensureWorkOrders().map((order) => ({ ...order, target: { ...order.target }, destination: { ...order.destination }, data: { ...order.data } })),
      createLaborOrder: (options = {}) => {
        const order = createWorkOrder(options);
        claimNextLaborWork();
        persist();
        render();
        return { ...order };
      },
      syncLaborOrders: () => {
        const changed = syncAutomaticCollectionServiceOrders() + syncLaborTaskOrders();
        const claimed = claimNextLaborWork();
        persist();
        render();
        return { changed, claimed };
      },
      advanceSimulation: (seconds) => {
        advanceTime(seconds, { quiet: true });
        persist();
        render();
        return state.clock;
      },
      queueDoorOperation: (doorId, operation, value, options = {}) => queueDoorOperation(doorId, operation, value, options),
      materialCatalog: () => MATERIAL_DEFS.map((material) => ({ ...material, properties: { ...material.properties } })),
      toolMaterialSnapshot: (itemKey) => ({
        itemKey,
        composition: toolMaterialComposition(itemKey),
        properties: Object.fromEntries(MATERIAL_PROPERTY_DEFS.map((property) => [property.id, compositionPropertyScore(toolMaterialComposition(itemKey), property.id)])),
        resistances: Object.fromEntries(DAMAGE_TYPE_DEFS.map((type) => [type.id, handlingMethodDamageResistanceScore(Object.entries(HANDLING_METHOD_INVENTORY_ITEM_KEYS).find(([, key]) => key === itemKey)?.[0] || "bareHands", type.id)]))
      }),
      constructionToolSnapshot: () => Object.entries(ensureToolDurability()).flatMap(([itemKey, instances]) =>
        instances.filter(() => durableToolDef(itemKey)?.capabilities).map((instance) => ({
          itemKey,
          label: inventoryItemLabel(itemKey),
          instance: { ...instance },
          qualityBand: toolQualityBand(instance).label,
          conditionBand: toolConditionBand(instance).label,
          capabilities: { ...(durableToolDef(itemKey)?.capabilities || {}) },
          composition: toolMaterialComposition(itemKey)
        }))
      ),
      fixtureSnapshot: () => ({
        fixtures: (state.fixtures || []).map((fixture) => ({
          ...fixture,
          definition: fixtureDef(fixture),
          footprintCells: fixtureFootprintCells(fixture),
          ports: fixturePortCells(fixture),
          accessiblePorts: fixtureAccessCells(fixture)
        })),
        productionBills: (state.productionBills || []).map((bill) => ({ ...bill })),
        productionWorkpieces: (state.productionWorkpieces || []).map((workpiece) => ({ ...workpiece })),
        recipes: PRODUCTION_RECIPE_DEFS.map((recipe) => ({ ...recipe, materialOptions: recipe.materialOptions.map((option) => ({ ...option })) })),
        fabricatedFixtures: (state.fabricatedFixtures || []).map((item) => ({ ...item }))
      }),
      infrastructureSnapshot: () => {
        const context = utilityNetworkContext();
        return {
          fixtures: (state.fixtures || []).filter(fixtureInfrastructureDef).map((fixture) => ({
            id: fixture.id,
            typeId: fixture.typeId,
            name: fixture.name,
            origin: { ...fixture.origin },
            utility: {
              ...fixture.utility,
              contents: { ...fixture.utility.contents },
              capturedAirborne: { ...fixture.utility.capturedAirborne }
            },
            networks: fixtureUtilityNetworks(fixture),
            components: Object.fromEntries(fixtureUtilityNetworks(fixture).map((medium) => {
              const component = utilityComponentForFixture(fixture, medium, context);
              return [medium, component?.fixtures?.map((member) => member.id) || []];
            }))
          }))
        };
      },
      setFixtureUtility: (fixtureId, changes = {}) => updateFixtureUtility(fixtureId, changes),
      physicalStockSnapshot: () => ({
        designations: ensureStockpileDesignations().map((designation) => ({
          ...designation,
          cells: designation.cells.map((cell) => ({ ...cell })),
          roomId: stockpileDesignationRoomId(designation),
          filterLabel: STOCKPILE_FILTER_PRESET_BY_ID[designation.filterPresetId]?.label || designation.filterPresetId
        })),
        fixtures: (state.fixtures || []).filter(isStorageFixture).map((fixture) => ({
          id: fixture.id,
          name: fixture.name,
          typeId: fixture.typeId,
          accessState: fixture.accessState,
          roomId: labMapCellRoomId(fixture.origin),
          capacity: { ...storageFixtureDef(fixture).storage },
          usage: storageFixtureUsage(fixture),
          contents: physicalStacksInFixture(fixture.id).map((stack) => ({ ...stack, exposed: physicalStackExposed(stack), storedCorrectly: physicalStackStoredCorrectly(stack) }))
        })),
        floorStacks: ensurePhysicalItemStacks().filter((stack) => !stack.fixtureId && !stack.carriedBy).map((stack) => ({ ...stack, exposed: physicalStackExposed(stack), storedCorrectly: physicalStackStoredCorrectly(stack) })),
        carriedStacks: ensurePhysicalItemStacks().filter((stack) => stack.carriedBy).map((stack) => ({ ...stack, exposed: false, storedCorrectly: true })),
        stacks: ensurePhysicalItemStacks().map((stack) => ({ ...stack, exposed: physicalStackExposed(stack), storedCorrectly: physicalStackStoredCorrectly(stack) })),
        activeHaul: stockpileHaulTask() ? { ...stockpileHaulTask(), data: { ...stockpileHaulTask().data } } : null,
        tileOccupancy: (cell) => ({
          cell: cleanMapCell(cell),
          occupiedM2: tileOccupiedAreaM2(cell),
          capacityM2: MAP_TILE_AREA_M2,
          scientistFits: canActorOccupyTile(state.scientist, cell)
        })
      }),
      tileEnvironmentSnapshot: (cell = null) => {
        const map = ensureLabMap();
        const environments = ensureTileEnvironments(map);
        const records = cell ? [tileEnvironmentAtCell(cell, map)].filter(Boolean) : Object.values(environments);
        return records.map((record) => ({
          ...record,
          cell: { ...record.cell },
          airborne: { ...record.airborne },
          chemicalTraces: { ...record.chemicalTraces },
          chemicalTraceTotal: chemicalTraceTotal(record.chemicalTraces),
          airborneTotal: airborneLoadTotal(record.airborne),
          substances: Object.entries(record.airborne).map(([id, concentration]) => ({ id, label: airborneSubstanceLabel(id), concentration }))
        }));
      },
      setTileEnvironment: (cell, values = {}) => {
        const record = tileEnvironmentAtCell(cell);
        if (!record) return false;
        if (Number.isFinite(Number(values.temperatureC))) record.temperatureC = clamp(Number(values.temperatureC), -100, 500);
        if (Number.isFinite(Number(values.rockTemperatureC))) record.rockTemperatureC = clamp(Number(values.rockTemperatureC), -100, 100);
        if (Number.isFinite(Number(values.humidity))) record.humidity = clamp(Number(values.humidity), 0, 100);
        if (Number.isFinite(Number(values.manaDensity))) record.manaDensity = clamp(Number(values.manaDensity), 0, 1000);
        if (Number.isFinite(Number(values.rockManaDensity))) record.rockManaDensity = clamp(Number(values.rockManaDensity), 0, 1000);
        if (values.airborne) record.airborne = normalizeAirborneLoads(values.airborne);
        if (values.chemicalTraces) record.chemicalTraces = normalizeChemicalTraces(values.chemicalTraces);
        record.updatedAt = state.clock;
        syncRoomAttributeSummaries();
        persist();
        render();
        return true;
      },
      addAirborneSubstance: (cell, substanceId, concentration) => {
        const changed = adjustTileEnvironmentAtCell(cell, "contamination", concentration, { substanceId });
        syncRoomAttributeSummaries();
        persist();
        render();
        return changed;
      },
      addPhysicalSpill: (cell, quantity = 1, key = "hazardousSludge", tags = ["debug-spill"]) => {
        const clean = cleanMapCell(cell);
        const roomId = labMapCellRoomId(clean);
        if (!clean || !roomId) return null;
        const stack = createPhysicalItemStack("residue", key, Math.max(0.01, Number(quantity) || 1), {
          roomId,
          cell: clean,
          fixtureId: "",
          containerId: "",
          carriedBy: ""
        }, {
          form: "spill",
          tags,
          knownQuantity: Math.max(0.01, Number(quantity) || 1)
        });
        persist();
        render();
        return stack ? { ...stack, cell: { ...stack.cell }, tags: [...stack.tags] } : null;
      },
      airborneMassSnapshot: () => {
        const totals = {};
        const tileVolume = tileEnvironmentVolumeM3();
        for (const record of Object.values(ensureTileEnvironments())) {
          for (const [id, concentration] of Object.entries(record.airborne || {})) totals[id] = (totals[id] || 0) + concentration * tileVolume;
        }
        for (const container of state.containers || []) {
          const volume = containerInteriorVolumeM3(container);
          for (const [id, concentration] of Object.entries(container.environment?.airborne || {})) totals[id] = (totals[id] || 0) + concentration * volume;
        }
        return totals;
      },
      actorSpaceSnapshot: (actorId, cell) => {
        const actor = actorId === "scientist" ? state.scientist : findSlime(actorId);
        return actor ? {
          actorId,
          cell: cleanMapCell(cell),
          floorLoadM2: actorFloorLoadM2(actor),
          occupiedM2: tileOccupiedAreaM2(cell, { excludeActor: actor }),
          fits: canActorOccupyTile(actor, cell)
        } : null;
      },
      genomeSpaceSnapshot: (genome, cell, mass = 100) => {
        const actor = { genome, stats: { currentMass: { current: mass, max: 100 } } };
        return {
          genome,
          cell: cleanMapCell(cell),
          floorLoadM2: slimeFloorLoadM2(actor),
          occupiedM2: tileOccupiedAreaM2(cell),
          fits: tileOccupiedAreaM2(cell) + slimeFloorLoadM2(actor) <= MAP_TILE_AREA_M2 + TILE_OCCUPANCY_EPSILON
        };
      },
      fulfillFixtureProductionBill: (billId) => fulfillFixtureProductionBill(billId),
      createProductionBill: (options) => createProductionBill(options),
      setProductionBillStatus: (billId, status) => setProductionBillStatus(billId, status),
      advanceSimulation: (seconds) => {
        advanceTime(Math.max(0, Number(seconds) || 0), { quiet: true });
        persist();
        render();
        return true;
      },
      damageTool: (itemKey, amount) => {
        const tool = bestToolInstance(itemKey, true);
        const result = tool ? damageSpecificTool(tool.id, amount, "debug damage") : null;
        refreshConstructionOrderBlocks();
        persist();
        render();
        return result;
      },
      structuralSnapshot: (cell) => {
        const target = structuralTargetAtCell(cleanMapCell(cell));
        if (!target) return null;
        const composition = structuralTargetComposition(target);
        const condition = structuralTargetCondition(target);
        return {
          kind: target.kind,
          cell: target.cell,
          composition,
          condition,
          state: structureConditionBand(condition),
          attackTransmission: wallAllowsAttackTransmission(target.cell),
          resistances: Object.fromEntries(DAMAGE_TYPE_DEFS.map((type) => [type.id, structureDamageResistanceScore(target, type.id)])),
          properties: Object.fromEntries(MATERIAL_PROPERTY_DEFS.map((property) => [property.id, compositionPropertyScore(composition, property.id)]))
        };
      },
      damageStructure: (cell, amount, damageTypeId = "physical") => debugDamageStructure(cleanMapCell(cell), damageTypeId, amount),
      sensorySnapshot: (actorId = "scientist") => {
        const actor = actorId === "scientist" ? state.scientist : findSlime(actorId);
        if (!actor) return null;
        const actorType = actorId === "scientist" ? "scientist" : "slime";
        const sensory = normalizeSensoryState(actor.sensory, actorType, actor.genome || "");
        return JSON.parse(JSON.stringify({ actorId, actorType, sensory }));
      }
    };
  }

