    quiesce: "remain quiescent",
    recover: "recover",
    acclimate: "acclimate",
    wander: "wander",
    seekFood: "seek food",
    seekHabitat: "seek habitat",
    feed: "feed",
    endureContainment: "endure containment",
    endureHabitat: "endure habitat",
    hunt: "hunt",
    fight: "fight",
